"use client";
import { useState, useEffect } from "react";

const AFFILIATE_ID = "17395950528";
const SUB_ID = "MEOZZ";
const PRODUCT_RE = /shopee\.vn\/(?:product|opaanlp)\/(\d+)\/(\d+)/;

function extractShopProduct(url) {
  const m = url.match(PRODUCT_RE);
  return m ? { shopId: m[1], productId: m[2] } : null;
}

function buildAffiliate(shopId, productId) {
  const origin = `https://shopee.vn/product/${shopId}/${productId}`;
  return {
    success: true, shopId, productId, originLink: origin,
    affiliateLink: `https://s.shopee.vn/an_redir?origin_link=${encodeURIComponent(origin)}&affiliate_id=${AFFILIATE_ID}&sub_id=${SUB_ID}`,
  };
}

function processClientSide(link) {
  let ids = extractShopProduct(link);
  if (ids) return buildAffiliate(ids.shopId, ids.productId);
  const m1 = link.match(/origin_link=([^&]+)/);
  if (m1) { ids = extractShopProduct(decodeURIComponent(m1[1])); if (ids) return buildAffiliate(ids.shopId, ids.productId); }
  const m2 = link.match(/[?&]next=([^&]+)/);
  if (m2) { ids = extractShopProduct(decodeURIComponent(m2[1])); if (ids) return buildAffiliate(ids.shopId, ids.productId); }
  return null;
}

const VOUCHERS = [
  { pct: "20%", max: "250kđ", min: "Đơn tối thiểu 50kđ", color: "#1877f2", label: "Phổ biến nhất", used: 77, expire: "Còn 1 ngày" },
  { pct: "22%", max: "500kđ", min: "Đơn tối thiểu 50kđ", color: "#e05a00", label: "Ưu đãi tốt", used: 85, expire: "Còn vài giờ" },
];

const VOUCHER_IMAGES = {
  "20%": "data:image/png;base64,",
  "22%": "data:image/png;base64,",
};

function VoucherCard({ v }) {
  const imgSrc = VOUCHER_IMAGES[v.pct];
  return (
    <div style={{
      borderRadius: 14, overflow: "hidden",
      marginBottom: 12, boxShadow: "0 2px 12px rgba(0,0,0,.10)", background: "#fff",
    }}>
      <img src={imgSrc} alt={`Mã giảm giá ${v.pct}`} style={{ width: "100%", display: "block" }} />
    </div>
  );
}

export default function Home() {
  const [input, setInput] = useState("");
  const [results, setResults] = useState([]);
  const [loading, setLoading] = useState(false);
  const [copiedIdx, setCopiedIdx] = useState(null);
  const [copiedAll, setCopiedAll] = useState(false);
  const [tab, setTab] = useState("convert");

  useEffect(() => {
    fetch("/api/convert", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ links: [] }) }).catch(() => {});
    const t = setInterval(() => {
      fetch("/api/convert", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ links: [] }) }).catch(() => {});
    }, 4 * 60 * 1000);
    return () => clearInterval(t);
  }, []);

  async function convert() {
    const links = input.split("\n").map((l) => l.trim()).filter(Boolean).slice(0, 10);
    if (!links.length) return alert("Vui lòng dán ít nhất 1 link Shopee!");
    setLoading(true);
    setResults([]);
    const clientResults = links.map(link => processClientSide(link));
    const needApi = links.filter((_, i) => !clientResults[i]);
    let apiResults = [];
    if (needApi.length > 0) {
      try {
        const res = await fetch("/api/convert", {
          method: "POST", headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ links: needApi }),
        });
        const data = await res.json();
        apiResults = data.results || [];
      } catch {
        apiResults = needApi.map(link => ({ input: link, success: false, error: "Lỗi kết nối" }));
      }
    }
    let apiIdx = 0;
    const final = links.map((link, i) => {
      if (clientResults[i]) return { ...clientResults[i], input: link };
      return apiResults[apiIdx++] || { input: link, success: false, error: "Lỗi không xác định" };
    });
    setResults(final);
    setLoading(false);
  }

  async function copyOne(idx, link) {
    await navigator.clipboard.writeText(link);
    setCopiedIdx(idx);
    setTimeout(() => setCopiedIdx(null), 2000);
  }

  async function copyAll() {
    const links = results.filter((r) => r.success).map((r) => r.affiliateLink).join("\n");
    await navigator.clipboard.writeText(links);
    setCopiedAll(true);
    setTimeout(() => setCopiedAll(false), 2000);
  }

  const successCount = results.filter((r) => r.success).length;

  const TABS = [
    { key: "convert", label: "🔄 Chuyển link" },
    { key: "vouchers", label: "🎁 Mã giảm giá" },
  ];

  return (
    <main style={{ minHeight: "100vh", background: "#d6eef8", fontFamily: "'Be Vietnam Pro', sans-serif" }}>

      {/* ── HEADER ── */}
      <div style={{ background: "transparent", padding: "28px 20px 0", textAlign: "center" }}>
        <p style={{ fontSize: 17, fontWeight: 800, fontStyle: "italic", color: "#e8306a", lineHeight: 1.5, margin: 0 }}>
          Đổi link Shopee săn mã giảm giá 20% 22% cùng<br />Meozz
        </p>
      </div>

      {/* ── TABS ── */}
      <div style={{ maxWidth: 500, margin: "18px auto 0", padding: "0 16px" }}>
        <div style={{ display: "flex", background: "rgba(255,255,255,.45)", borderRadius: 14, padding: 4, gap: 4 }}>
          {TABS.map(({ key, label }) => (
            <button key={key} onClick={() => setTab(key)} style={{
              flex: 1, padding: "10px 0", border: "none", borderRadius: 10,
              background: tab === key ? "#fff" : "transparent",
              color: tab === key ? "#e05a00" : "#888",
              fontWeight: 700, fontSize: 14, cursor: "pointer",
              fontFamily: "inherit",
              boxShadow: tab === key ? "0 2px 8px rgba(0,0,0,.10)" : "none",
              transition: "all .2s",
            }}>
              {label}
            </button>
          ))}
        </div>
      </div>

      {/* ── BODY ── */}
      <div style={{ maxWidth: 500, margin: "0 auto", padding: "16px 16px 48px" }}>

        {/* ══ CONVERT TAB ══ */}
        {tab === "convert" && (
          <>
            {/* Input card */}
            <div style={{ background: "#fff", borderRadius: 20, padding: "18px 16px 14px", boxShadow: "0 2px 16px rgba(0,0,0,.07)", marginBottom: 14 }}>
              {/* Single-line input with copy icon */}
              <div style={{ display: "flex", alignItems: "center", border: "1.5px solid #e0e0e0", borderRadius: 12, padding: "10px 14px", background: "#f9f9f9", marginBottom: 14 }}>
                <input
                  type="text"
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  onKeyDown={(e) => e.key === "Enter" && convert()}
                  placeholder="Dán link Shopee để nhận mã giảm giá"
                  style={{
                    flex: 1, border: "none", background: "transparent", fontSize: 14,
                    color: "#222", outline: "none", fontFamily: "inherit",
                  }}
                />
                <button
                  onClick={async () => { try { const t = await navigator.clipboard.readText(); setInput(t); } catch {} }}
                  style={{ background: "none", border: "none", cursor: "pointer", padding: "2px 4px", display: "flex", alignItems: "center" }}
                  title="Dán từ clipboard"
                >
                  {/* Clipboard icon */}
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="#bbb" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                    <rect x="9" y="2" width="6" height="4" rx="1" /><path d="M9 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V4a2 2 0 0 0-2-2h-3" />
                  </svg>
                </button>
              </div>

              {/* CHUYỂN ĐỔI NGAY button */}
              <button
                onClick={convert}
                disabled={loading}
                style={{
                  width: "100%", background: loading ? "#f0a080" : "#e05a00",
                  color: "#fff", border: "none", borderRadius: 14,
                  padding: "16px 0", fontSize: 16, fontWeight: 800,
                  letterSpacing: 1.5, cursor: loading ? "not-allowed" : "pointer",
                  fontFamily: "inherit", boxShadow: "0 4px 16px rgba(224,90,0,.30)",
                  transition: "background .2s",
                }}
              >
                {loading ? "⏳ ĐANG XỬ LÝ..." : "CHUYỂN ĐỔI NGAY"}
              </button>

              {/* Multi-link hint */}
              <div style={{ textAlign: "center", marginTop: 10, fontSize: 11, color: "#bbb" }}>
                Chưa đến 1 giây là xong, hãy nhập 1 link thôi bạn nhé
              </div>

              {/* Textarea for multi-link (hidden behind single input visually, shown as hint) */}
              {input.includes("\n") && (
                <textarea
                  style={{
                    marginTop: 10, width: "100%", border: "1.5px solid #e0e0e0", borderRadius: 12,
                    padding: "10px 14px", fontFamily: "inherit", fontSize: 13, lineHeight: 1.6,
                    resize: "none", background: "#f9f9f9", color: "#222", outline: "none", boxSizing: "border-box",
                  }}
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  rows={4}
                />
              )}
            </div>

            {/* ── Results ── */}
            {results.length > 0 && (
              <div style={{ marginBottom: 16 }}>
                {results.map((r, i) => (
                  <div key={i} style={{
                    background: "#fff", borderRadius: 16, padding: "14px 16px", marginBottom: 12,
                    boxShadow: "0 2px 12px rgba(0,0,0,.08)",
                    borderLeft: `4px solid ${r.success ? "#e05a00" : "#fa3e3e"}`,
                  }}>
                    {r.success ? (
                      <>
                        {/* Status badge */}
                        <div style={{
                          display: "inline-flex", alignItems: "center", gap: 5,
                          background: "#e8f8ef", borderRadius: 20, padding: "3px 10px",
                          fontSize: 12, fontWeight: 700, color: "#27ae60", marginBottom: 10,
                        }}>
                          <span>✓</span> Đã chuyển đổi xong
                        </div>
                        {/* Affiliate link */}
                        <div style={{ fontSize: 12, color: "#666", wordBreak: "break-all", lineHeight: 1.6, marginBottom: 12 }}>
                          {r.affiliateLink}
                        </div>
                        {/* SAO CHÉP LINK button */}
                        <button
                          onClick={() => copyOne(i, r.affiliateLink)}
                          style={{
                            width: "100%", background: copiedIdx === i ? "#27ae60" : "#e05a00",
                            color: "#fff", border: "none", borderRadius: 12,
                            padding: "13px 0", fontSize: 15, fontWeight: 800,
                            letterSpacing: 1, cursor: "pointer", fontFamily: "inherit",
                            boxShadow: "0 3px 12px rgba(224,90,0,.25)", transition: "background .2s",
                            display: "flex", alignItems: "center", justifyContent: "center", gap: 8,
                          }}
                        >
                          {copiedIdx === i ? (
                            "✅ ĐÃ SAO CHÉP!"
                          ) : (
                            <>
                              {/* Link icon */}
                              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                                <path d="M10 13a5 5 0 0 0 7.54.54l3-3a5 5 0 0 0-7.07-7.07l-1.72 1.71" />
                                <path d="M14 11a5 5 0 0 0-7.54-.54l-3 3a5 5 0 0 0 7.07 7.07l1.71-1.71" />
                              </svg>
                              SAO CHÉP LINK
                            </>
                          )}
                        </button>
                      </>
                    ) : (
                      <div style={{ fontSize: 13, color: "#fa3e3e", fontWeight: 600 }}>❌ {r.error}</div>
                    )}
                  </div>
                ))}

                {successCount > 1 && (
                  <button
                    onClick={copyAll}
                    style={{
                      width: "100%", background: "transparent", border: `2px solid ${copiedAll ? "#27ae60" : "#e05a00"}`,
                      borderRadius: 12, padding: "12px 0", fontSize: 14, fontWeight: 800,
                      color: copiedAll ? "#27ae60" : "#e05a00", cursor: "pointer",
                      fontFamily: "inherit", letterSpacing: 0.5,
                    }}
                  >
                    {copiedAll ? "✅ Đã sao chép tất cả!" : "📋 Sao chép tất cả link"}
                  </button>
                )}
              </div>
            )}

            {/* ── Voucher tip box ── */}
            <div style={{
              background: "#fff", borderRadius: 16, padding: "14px 16px",
              boxShadow: "0 2px 10px rgba(0,0,0,.07)",
              border: "1.5px dashed #f4a261",
            }}>
              <div style={{ fontSize: 13, color: "#555", lineHeight: 1.7, marginBottom: 10 }}>
                💡 Bạn hãy nhấn "<span style={{ color: "#e05a00", fontWeight: 700 }}>🔗 Sao chép link</span>" và dán vào dưới bình luận của bài viết này sau đó click vào link đó app mã rồi mua hàng nhé:
              </div>
              <a
                href="https://www.facebook.com/share/p/18o9LakWMj/?mibextid=wwXIfr"
                target="_blank" rel="noopener noreferrer"
                style={{ fontSize: 13, color: "#1877f2", wordBreak: "break-all" }}
              >
                https://www.facebook.com/share/p/18o9LakWMj/?mibextid=wwXIfr
              </a>
            </div>

            {/* ── Real voucher images in convert tab ── */}
            <div style={{ marginTop: 12 }}>
              {VOUCHERS.map((v, i) => <VoucherCard key={i} v={v} />)}
            </div>
          </>
        )}

        {/* ══ VOUCHERS TAB ══ */}
        {tab === "vouchers" && (
          <>
            <div style={{ background: "#fff", borderRadius: 16, overflow: "hidden", marginBottom: 16, boxShadow: "0 2px 10px rgba(0,0,0,.08)" }}>
              <div style={{ background: "linear-gradient(135deg,#e05a00,#f4a261)", padding: "14px 16px", display: "flex", alignItems: "center", gap: 10 }}>
                <div style={{ width: 36, height: 36, borderRadius: "50%", background: "rgba(255,255,255,.2)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 18 }}>🎁</div>
                <div>
                  <div style={{ color: "#fff", fontWeight: 700, fontSize: 14 }}>Ưu đãi độc quyền hôm nay</div>
                  <div style={{ color: "rgba(255,255,255,.8)", fontSize: 11 }}>Chỉ áp dụng khi mua qua link affiliate</div>
                </div>
                <div style={{ marginLeft: "auto", background: "#ff3b30", color: "#fff", fontSize: 10, fontWeight: 800, padding: "3px 8px", borderRadius: 20 }}>HOT</div>
              </div>
              <div style={{ padding: "12px 16px", display: "flex", gap: 10 }}>
                {VOUCHERS.map((v) => (
                  <div key={v.pct} style={{ flex: 1, textAlign: "center", background: "#fff8f5", borderRadius: 10, padding: "10px 4px", border: `1.5px solid ${v.color}33` }}>
                    <div style={{ fontSize: 20, fontWeight: 900, color: v.color }}>{v.pct}</div>
                    <div style={{ fontSize: 9, color: "#888", fontWeight: 600 }}>GIẢM</div>
                  </div>
                ))}
              </div>
            </div>

            <div style={{ fontSize: 13, fontWeight: 700, color: "#444", marginBottom: 10 }}>Mã giảm giá đang có:</div>
            {VOUCHERS.map((v, i) => <VoucherCard key={i} v={v} />)}

            <div style={{ background: "#fff", borderRadius: 14, padding: 16, boxShadow: "0 2px 8px rgba(0,0,0,.07)", marginBottom: 14 }}>
              <div style={{ fontSize: 13, fontWeight: 800, color: "#e05a00", marginBottom: 12 }}>📖 Cách nhận giảm giá</div>
              {[
                ["🔗", "Chuyển link Shopee của bạn tại tab \"Chuyển link\""],
                ["📤", "Sao chép link chuyển đổi dán lên bài viết Facebook"],
                ["🛒", "Người mua hàng qua link đó được giảm ngay 20–22%"],
                ["💰", "Bạn tiết kiệm được 1 khoản tiền kha khá khi mua hàng!"],
              ].map(([icon, text]) => (
                <div key={icon} style={{ display: "flex", gap: 10, marginBottom: 10, alignItems: "flex-start" }}>
                  <span style={{ fontSize: 16, flexShrink: 0 }}>{icon}</span>
                  <span style={{ fontSize: 13, color: "#444", lineHeight: 1.5 }}>{text}</span>
                </div>
              ))}
            </div>

            <button
              onClick={() => setTab("convert")}
              style={{
                width: "100%", background: "#e05a00", color: "#fff", border: "none",
                borderRadius: 14, padding: "14px 0", fontSize: 15, fontWeight: 800,
                cursor: "pointer", fontFamily: "inherit", letterSpacing: 0.5,
                boxShadow: "0 4px 14px rgba(224,90,0,.30)",
              }}
            >
              🔄 Chuyển link ngay để nhận ưu đãi →
            </button>
          </>
        )}
      </div>
    </main>
  );
}
